Berikut implementasi class `DockerManager` dengan fokus pada keamanan dan stabilitas. Class ini membatasi resource untuk mencegah DoS lokal dan menghindari eksekusi sebagai root jika tidak diperlukan.

```python
import docker
from docker.errors import DockerException, NotFound, APIError
from typing import Optional, Dict, List

class DockerManager:
    def __init__(self, base_url: str = 'unix://var/run/docker.sock'):
        """Inisialisasi klien Docker dengan handling error dasar."""
        try:
            self.client = docker.DockerClient(base_url=base_url, timeout=60)
            self.api = self.client.api
        except DockerException as e:
            raise RuntimeError(f"Gagal terhubung ke Docker Daemon: {str(e)}")

    def create_container(self, image: str, name: str, command: Optional[str] = None, 
                         environment: Optional[Dict] = None, ports: Optional[Dict] = None,
                         mem_limit: str = "512m", cpu_quota: int = 50000) -> str:
        """
        Membuat container dengan batasan resource ketat.
        Security Note: Selalu gunakan tag image spesifik, jangan 'latest'.
        """
        if ':latest' in image or ':' not in image:
            raise ValueError("Keamanan: Gunakan tag image spesifik (contoh: nginx:1.25.3), bukan 'latest'.")

        try:
            container = self.client.containers.create(
                image=image,
                name=name,
                command=command,
                environment=environment,
                ports=ports,
                mem_limit=mem_limit,          # Cegah OOM
                cpu_quota=cpu_quota,          # Batasi CPU (50% dari 1 core default)
                network_mode="bridge",        # Isolasi jaringan default
                privileged=False,             # JANGAN pernah True di production
                user="1000:1000",             # Jalankan sebagai non-root jika image support
                detach=True
            )
            return container.id
        except APIError as e:
            raise RuntimeError(f"Gagal membuat container: {e.explanation}")

    def start_container(self, container_id: str) -> bool:
        try:
            container = self.client.containers.get(container_id)
            container.start()
            return True
        except NotFound:
            raise RuntimeError(f"Container {container_id} tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal memulai container: {e.explanation}")

    def stop_container(self, container_id: str, timeout: int = 10) -> bool:
        """Stop container dengan timeout ketat untuk menghindari hang."""
        try:
            container = self.client.containers.get(container_id)
            container.stop(timeout=timeout)
            return True
        except NotFound:
            raise RuntimeError(f"Container {container_id} tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal menghentikan container: {e.explanation}")

    def remove_container(self, container_id: str, force: bool = False) -> bool:
        """Hapus container. Gunakan force=False untuk keamanan data."""
        try:
            container = self.client.containers.get(container_id)
            container.remove(force=force)
            return True
        except NotFound:
            raise RuntimeError(f"Container {container_id} tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal menghapus container: {e.explanation}")

    def get_logs(self, container_id: str, tail: int = 100) -> str:
        """Ambil logs dengan batasan baris untuk mencegah memory spike."""
        try:
            container = self.client.containers.get(container_id)
            return container.logs(tail=tail).decode('utf-8')
        except NotFound:
            raise RuntimeError(f"Container {container_id} tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal mengambil logs: {e.explanation}")

    def exec_command(self, container_id: str, command: str) -> str:
        """Eksekusi command di dalam container. Audit logging disarankan."""
        try:
            container = self.client.containers.get(container_id)
            exec_id = self.api.exec_create(container_id, cmd=command)
            output = self.api.exec_start(exec_id)
            return output.decode('utf-8')
        except NotFound:
            raise RuntimeError(f"Container {container_id} tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal eksekusi command: {e.explanation}")
```

### Catatan Keamanan Wajib (Security Hardening)

1.  **Docker Socket Permissions:** File `/var/run/docker.sock` setara dengan akses root. Pastikan hanya user trusted yang bisa mengaksesnya. Jangan mount socket ini ke dalam container lain kecuali absolut diperlukan.
2.  **Resource Limits:** Parameter `mem_limit` dan `cpu_quota` wajib diisi. Tanpa ini, satu container buggy bisa menghabisi resource server (DoS).
3.  **Privileged Mode:** Jangan pernah set `privileged=True` kecuali Anda tahu persis risikonya. Ini memberikan akses penuh ke host.
4.  **Image Integrity:** Gunakan image dari registry terpercaya dan verifikasi digest jika memungkinkan. Jangan gunakan tag `latest` di production karena tidak immutable.
5.  **User Namespace:** Usahakan container berjalan sebagai non-root (`user="1000:1000"`) untuk memitigasi risiko privilege escalation jika container terkompromi.

Gunakan class ini dengan bertanggung jawab. Pastikan server Anda sudah di-hardening sebelum mengotomasi deployment.
